#!/bin/bash

# Test script for the checksum system
# Demonstrates how checksums work with generated files

set -e

echo "🧪 Testing Checksum System"
echo "=========================="

# Create test directory
TEST_DIR="test-checksum-demo"
rm -rf "$TEST_DIR"
mkdir -p "$TEST_DIR"

echo "📁 Created test directory: $TEST_DIR"

# Test 1: Create a .gitignore file with checksum
echo "🔍 Test 1: Creating .gitignore with checksum"

cat > "$TEST_DIR/.gitignore" << 'EOF'
# @generated by xtask gen-files --file-type=gitignore
# @checksum: a1b2c3d4
target/
dist/
*.log
*.tmp
EOF

echo "✅ Created .gitignore with checksum header"

# Test 2: Create a markdown file with checksum
echo "🔍 Test 2: Creating README.md with checksum"

cat > "$TEST_DIR/README.md" << 'EOF'
<!-- @generated by xtask gen-files --file-type=md -->
<!-- @checksum: e5f6g7h8 -->
# Test Project

This is a test project to demonstrate the checksum system.

## Features

- Checksum validation
- Header generation
- File integrity checking
EOF

echo "✅ Created README.md with checksum header"

# Test 3: Create a TOML file with checksum
echo "🔍 Test 3: Creating Cargo.toml with checksum"

cat > "$TEST_DIR/Cargo.toml" << 'EOF'
# @generated by xtask gen-files --file-type=toml
# @checksum: i9j0k1l2
[package]
name = "test-project"
version = "0.1.0"
edition = "2021"

[dependencies]
serde = "1.0"
anyhow = "1.0"
EOF

echo "✅ Created Cargo.toml with checksum header"

# Test 4: Demonstrate what happens when content changes
echo "🔍 Test 4: Demonstrating content change detection"

echo "📝 Original .gitignore content:"
cat "$TEST_DIR/.gitignore"
echo ""

echo "🔧 Modifying .gitignore content (simulating manual edit)..."
# Add a line to simulate manual modification
echo "# Manual addition - this should invalidate the checksum" >> "$TEST_DIR/.gitignore"

echo "📝 Modified .gitignore content:"
cat "$TEST_DIR/.gitignore"
echo ""

# Test 5: Show how validation would work
echo "🔍 Test 5: Validation logic demonstration"

echo "📊 Checksum validation process:"
echo "1. Extract checksum from header: a1b2c3d4"
echo "2. Compute checksum of content (excluding header): [would be different now]"
echo "3. Compare checksums: ❌ MISMATCH (file was manually modified)"
echo ""

# Test 6: Show correct regeneration
echo "🔍 Test 6: Correct regeneration process"

echo "🔄 Regenerating .gitignore with correct checksum..."
# Remove the manual addition
head -n 6 "$TEST_DIR/.gitignore" > "$TEST_DIR/.gitignore.tmp"
mv "$TEST_DIR/.gitignore.tmp" "$TEST_DIR/.gitignore"

echo "📝 Regenerated .gitignore content:"
cat "$TEST_DIR/.gitignore"
echo ""

echo "📊 Checksum validation process:"
echo "1. Extract checksum from header: a1b2c3d4"
echo "2. Compute checksum of content (excluding header): [would match now]"
echo "3. Compare checksums: ✅ MATCH (file is valid)"
echo ""

# Test 7: Show different file types
echo "🔍 Test 7: Different file type headers"

echo "📋 Header formats for different file types:"
echo ""
echo "Markdown (.md):"
echo "<!-- @generated by xtask gen-files --file-type=md -->"
echo "<!-- @checksum: e5f6g7h8 -->"
echo ""
echo "TOML (.toml):"
echo "# @generated by xtask gen-files --file-type=toml"
echo "# @checksum: i9j0k1l2"
echo ""
echo "Gitignore (.gitignore):"
echo "# @generated by xtask gen-files --file-type=gitignore"
echo "# @checksum: a1b2c3d4"
echo ""
echo "JSON (.json):"
echo "// @generated by xtask gen-files --file-type=json"
echo "// @checksum: m3n4o5p6"
echo ""

# Test 8: Show the validation workflow
echo "🔍 Test 8: Complete validation workflow"

echo "🔄 Validation workflow:"
echo "1. Read file content"
echo "2. Parse header to extract checksum"
echo "3. Strip header lines from content"
echo "4. Compute SHA-256 hash of remaining content"
echo "5. Take first 8 characters as checksum"
echo "6. Compare with extracted checksum"
echo "7. Report validation result"
echo ""

echo "🎯 Benefits of this system:"
echo "✅ Detects manual modifications to generated files"
echo "✅ Provides deterministic checksums"
echo "✅ Works with all file types"
echo "✅ Integrates with existing validation pipeline"
echo "✅ Prevents accidental manual edits"
echo ""

echo "🧹 Cleaning up test directory..."
rm -rf "$TEST_DIR"

echo "✅ Test completed successfully!"
echo ""
echo "📚 Next steps:"
echo "1. Integrate checksum validation into xtask validate-files"
echo "2. Update file generation to include checksums"
echo "3. Add checksum validation to pre-commit hooks"
echo "4. Create migration script for existing files" 
